  describe('state invariants (stateful PBT)', () => {
    it('never: anchor-without-context', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ anchor: fc.string(), entityRef: fc.string({ minLength: 1, maxLength: 50 }), blockId: fc.string({ minLength: 1, maxLength: 50 }), offset: fc.integer({ min: 1, max: 1000 }), prefix: fc.string({ minLength: 1, maxLength: 50 }), suffix: fc.string({ minLength: 1, maxLength: 50 }), contentHash: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('resolve'), input: fc.record({ anchor: fc.string(), currentContent: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('relocate'), input: fc.record({ anchor: fc.string(), newBlockId: fc.string({ minLength: 1, maxLength: 50 }), newOffset: fc.integer({ min: 1, max: 1000 }), newContentHash: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('batchResolve'), input: fc.record({ entityRef: fc.string({ minLength: 1, maxLength: 50 }), currentContent: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ anchor: fc.string() }) }),
              fc.record({ action: fc.constant('delete'), input: fc.record({ anchor: fc.string() }) }),
              fc.record({ action: fc.constant('listForEntity'), input: fc.record({ entityRef: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = textAnchorHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(textAnchorHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
                // Never: anchor-without-context
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

    it('always: anchor-status-valid', async () => {
      await fc.assert(
        fc.asyncProperty(
          fc.array(
            fc.oneof(
              fc.record({ action: fc.constant('create'), input: fc.record({ anchor: fc.string(), entityRef: fc.string({ minLength: 1, maxLength: 50 }), blockId: fc.string({ minLength: 1, maxLength: 50 }), offset: fc.integer({ min: 1, max: 1000 }), prefix: fc.string({ minLength: 1, maxLength: 50 }), suffix: fc.string({ minLength: 1, maxLength: 50 }), contentHash: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('resolve'), input: fc.record({ anchor: fc.string(), currentContent: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('relocate'), input: fc.record({ anchor: fc.string(), newBlockId: fc.string({ minLength: 1, maxLength: 50 }), newOffset: fc.integer({ min: 1, max: 1000 }), newContentHash: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('batchResolve'), input: fc.record({ entityRef: fc.string({ minLength: 1, maxLength: 50 }), currentContent: fc.string({ minLength: 1, maxLength: 50 }) }) }),
              fc.record({ action: fc.constant('get'), input: fc.record({ anchor: fc.string() }) }),
              fc.record({ action: fc.constant('delete'), input: fc.record({ anchor: fc.string() }) }),
              fc.record({ action: fc.constant('listForEntity'), input: fc.record({ entityRef: fc.string({ minLength: 1, maxLength: 50 }) }) }),
            ),
            { minLength: 1, maxLength: 5 },
          ),
          async (actionSequence) => {
            const storage = createInMemoryStorage();
            for (const step of actionSequence) {
              const actionFn = textAnchorHandler[step.action];
              if (typeof actionFn === 'function') {
                const result = await safeInvoke(async () => {
                  const program = actionFn.call(textAnchorHandler, step.input as Record<string, unknown>);
                  return interpret(program, storage);
                });
                // Every action should return a result with a variant
                if (result?.variant !== undefined) {
                  expect(typeof result.variant).toBe('string');
                }
              }
            }
          },
        ),
        { numRuns: 50 },
      );
    });

  });

